const normalized = $('Normalize Telegram Update').first().json;
const userItems = $items('Load Active Telegram User');
const sessionItems = $items('Load User Session');
const agentItems = $items('Load User Agents');

const user = userItems[0]?.json || null;
const session = sessionItems[0]?.json || null;
const agents = agentItems.map(item => item.json);

return [
  {
    json: {
      ...normalized,
      user,
      session,
      agents,
      has_user: Boolean(user),
      has_agents: agents.length > 0
    },
    pairedItem: 0
  }
];

const checks = [
  'Load Active Telegram User',
  'Ensure User Session',
  'Load User Session',
  'Load User Agents'
];

const db_errors = [];
for (const nodeName of checks) {
  try {
    for (const item of $items(nodeName)) {
      if (item.json?.error || item.json?.message?.includes?.('SQL') || item.json?.code?.startsWith?.('ER_')) {
        db_errors.push({ node: nodeName, error: item.json.error || item.json.message || item.json.code });
      }
    }
  } catch (error) {}
}

return [{
  json: {
    ...$json,
    has_database_error: db_errors.length > 0,
    db_errors
  },
  pairedItem: 0
}];

const text = $json.message_text;
const data = $json.callback_data;
const pendingAction = $json.session?.pending_action;

const isFreeformCommand = typeof text === 'string' && !text.startsWith('/') && (
  /^(?:update|change|set)\s+(?:my\s+)?(?:agent\s+)?(?:prompt\s+)?(?:to\s+)?(?:answer|say|reply)\s+.+$/i.test(text) ||
  /^(?:update|change|set)\s+(?:my\s+)?(?:agent\s+)?prompt\s+(?:to|as)\s+.+$/i.test(text) ||
  /^(?:update|change|set)\s+(?:my\s+)?(?:agent\s+)?(?:welcome(?:\s+message)?|first\s+message)\s+(?:to|as)\s+.+$/i.test(text) ||
  /^(?:add|update|set)\s+(?:my\s+)?(?:agent\s+)?(?:knowledge(?:\s*base)?|content)\s+(?:to|as|with)\s+.+$/i.test(text)
);

let route = 'main_menu';
if (text === '/start') route = 'main_menu';
else if (text === '/menu') route = 'main_menu';
else if (text === '/cancel' || data === 'action:cancel') route = 'cancel';
else if (data === 'menu:select_agent') route = 'agent_list';
else if (typeof data === 'string' && data.startsWith('agent:select:')) route = 'select_agent';
else if (typeof data === 'string' && data.startsWith('action:')) route = 'start_pending_action';
else if ($json.has_unsupported_payload) route = 'unsupported_payload';
else if (text && !pendingAction && isFreeformCommand) route = 'freeform_command';
else if (text && pendingAction) route = 'complete_pending_action';

return [{ json: { ...$json, route }, pairedItem: 0 }];

