// Supported example: "update my agent to answer Hello world"
const text = ($json.message_text || '').trim();
const session = { ...($json.session || {}) };
const agents = $json.agents || [];

const patterns = [
  {
    action: 'update_welcome_message',
    regex: /^(?:update|change|set)\s+(?:my\s+)?(?:agent\s+)?(?:welcome(?:\s+message)?|first\s+message)\s+(?:to|as)\s+([\s\S]+)$/i
  },
  {
    action: 'update_knowledge_text',
    regex: /^(?:add|update|set)\s+(?:my\s+)?(?:agent\s+)?(?:knowledge(?:\s*base)?|content)\s+(?:to|as|with)\s+([\s\S]+)$/i
  },
  {
    action: 'update_prompt',
    regex: /^(?:update|change|set)\s+(?:my\s+)?(?:agent\s+)?prompt\s+(?:to|as)\s+([\s\S]+)$/i
  },
  {
    action: 'update_prompt',
    regex: /^(?:update|change|set)\s+(?:my\s+)?(?:agent\s+)?(?:prompt\s+)?(?:to\s+)?(?:answer|say|reply)\s+([\s\S]+)$/i
  }
];

let pending_action = null;
let update_text = null;
for (const pattern of patterns) {
  const match = text.match(pattern.regex);
  if (match) {
    pending_action = pattern.action;
    update_text = (match[1] || '').trim();
    break;
  }
}

const limits = {
  update_prompt: 4000,
  update_welcome_message: 500,
  update_knowledge_text: 2000
};
const labels = {
  update_prompt: 'Prompt',
  update_welcome_message: 'Welcome message',
  update_knowledge_text: 'Knowledge-base text'
};

let validation_error = null;
if (!pending_action) {
  validation_error = 'I could not understand that update command. Use the menu or write a command like: update my agent to answer Hello world';
} else if (!update_text) {
  validation_error = 'Send non-empty text for this update.';
} else if (pending_action === 'update_knowledge_text' && /^https?:\/\//i.test(update_text)) {
  validation_error = 'URL ingestion is not supported. Send plain text instead.';
} else if (update_text.length > limits[pending_action]) {
  validation_error = labels[pending_action] + ' must be ' + limits[pending_action].toLocaleString('en-US') + ' characters or fewer.';
}

if (!session.selected_voice_agent_id && agents.length === 1) {
  session.selected_voice_agent_id = agents[0].id;
}

const needs_agent_selection = !validation_error && !session.selected_voice_agent_id;
const freeform_route = validation_error
  ? 'validation_error'
  : needs_agent_selection
    ? 'agent_list'
    : 'complete_pending_action';

return [{
  json: {
    ...$json,
    session,
    requested_action: null,
    pending_action,
    update_text,
    validation_error,
    is_valid_update_text: validation_error === null,
    needs_agent_selection,
    freeform_route
  },
  pairedItem: 0
}];
